    worktree: "/tmp",
    branch: opts.session.branch ?? "main",
    status: opts.session.status,
    project: "my-app",
    runtimeHandle: opts.session.runtimeHandle
      ? JSON.stringify(opts.session.runtimeHandle)
      : undefined,
    ...opts.metaOverrides,
  };
  const persistedStringMetadata = Object.fromEntries(
